// Fetch prospects from Neon DB who need their next email
// Sequences: AI Automation (4 emails), Web Dev (3 emails), Directory (3 emails)
const sequences = {
  'ai-automation': [
    { day: 0, subject: 'Your {industry} business is manually doing what AI can automate', template: 'ai_cold_1' },
    { day: 3, subject: '3 automations every {industry} business should have', template: 'ai_cold_2' },
    { day: 7, subject: 'How a compliance company automated 80% of operations', template: 'ai_cold_3' },
    { day: 14, subject: 'Last note from me', template: 'ai_cold_4' }
  ],
  'web-dev': [
    { day: 0, subject: 'Your website is costing you clients', template: 'web_cold_1' },
    { day: 4, subject: 'What a $3K website should actually include', template: 'web_cold_2' },
    { day: 8, subject: 'Your competitors are investing in their online presence', template: 'web_cold_3' }
  ],
  'directory': [
    { day: 0, subject: 'A recurring-revenue business you can launch in 2 weeks', template: 'dir_cold_1' },
    { day: 4, subject: 'The math on a niche directory business', template: 'dir_cold_2' },
    { day: 10, subject: '5 niches that need a directory right now', template: 'dir_cold_3' }
  ]
};

// Replace with actual Neon DB query
return [{ json: { sequences, timestamp: new Date().toISOString() } }];

